import{M as e,c as t,d as n,h as r,k as i,m as a,p as o,t as s,u as c}from"./plugin-vue_export-helper-BVYGRoF1.js";var l=JSON.parse(`{"path":"/posts/2026/2026-05-04-tienda-daw-web.html","title":"Tienda Daw Web: Arquitectura Híbrida en .NET para DAW","lang":"es-ES","frontmatter":{"title":"Tienda Daw Web: Arquitectura Híbrida en .NET para DAW","description":"Un proyecto de referencia para el módulo de Desarrollo Web en Entornos Servidor (DWES) que integra MVC, Razor Pages y Blazor con las últimas tecnologías .NET","date":"2026-05-04T00:00:00.000Z","category":["Blog","Proyectos","Docencia"],"tag":[".NET","C#","DWES","Desarrollo Web Entorno Servidor","DAW","MVC","Razor","Blazor","Docker","NUnit","Playwright","CI/CD","Docencia"],"icon":"fa-solid fa-store","cover":"https://raw.githubusercontent.com/joseluisgs/TiendaDawWeb-NetCore/refs/heads/main/TiendaDawWeb.Mvc/wwwroot/images/slider02.jpg","comment":true,"sidebar":false,"footer":true,"head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Tienda Daw Web: Arquitectura Híbrida en .NET para DAW\\",\\"image\\":[\\"https://raw.githubusercontent.com/joseluisgs/TiendaDawWeb-NetCore/refs/heads/main/TiendaDawWeb.Mvc/wwwroot/images/slider02.jpg\\"],\\"datePublished\\":\\"2026-05-04T00:00:00.000Z\\",\\"dateModified\\":\\"2026-05-04T19:03:57.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"José Luis González Sánchez\\"}]}"],["meta",{"property":"og:url","content":"https://joseluisgs.dev/posts/2026/2026-05-04-tienda-daw-web.html"}],["meta",{"property":"og:site_name","content":"José Luis González"}],["meta",{"property":"og:title","content":"Tienda Daw Web: Arquitectura Híbrida en .NET para DAW"}],["meta",{"property":"og:description","content":"Un proyecto de referencia para el módulo de Desarrollo Web en Entornos Servidor (DWES) que integra MVC, Razor Pages y Blazor con las últimas tecnologías .NET"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://raw.githubusercontent.com/joseluisgs/TiendaDawWeb-NetCore/refs/heads/main/TiendaDawWeb.Mvc/wwwroot/images/slider02.jpg"}],["meta",{"property":"og:locale","content":"es-ES"}],["meta",{"property":"og:updated_time","content":"2026-05-04T19:03:57.000Z"}],["meta",{"name":"twitter:creator","content":"JoseLuisGSDev"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:image:src","content":"https://raw.githubusercontent.com/joseluisgs/TiendaDawWeb-NetCore/refs/heads/main/TiendaDawWeb.Mvc/wwwroot/images/slider02.jpg"}],["meta",{"name":"twitter:image:alt","content":"Tienda Daw Web: Arquitectura Híbrida en .NET para DAW"}],["meta",{"property":"article:tag","content":"Docencia"}],["meta",{"property":"article:tag","content":"CI/CD"}],["meta",{"property":"article:tag","content":"Playwright"}],["meta",{"property":"article:tag","content":"NUnit"}],["meta",{"property":"article:tag","content":"Docker"}],["meta",{"property":"article:tag","content":"Blazor"}],["meta",{"property":"article:tag","content":"Razor"}],["meta",{"property":"article:tag","content":"MVC"}],["meta",{"property":"article:tag","content":"DAW"}],["meta",{"property":"article:tag","content":"Desarrollo Web Entorno Servidor"}],["meta",{"property":"article:tag","content":"DWES"}],["meta",{"property":"article:tag","content":"C#"}],["meta",{"property":"article:tag","content":".NET"}],["meta",{"property":"article:published_time","content":"2026-05-04T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2026-05-04T19:03:57.000Z"}]]},"git":{"createdTime":1777916961000,"updatedTime":1777921437000,"contributors":[{"name":"José Luis González","username":"","email":"joseluisgonsan@gmail.com","commits":6}]},"readingTime":{"minutes":20.03,"words":6010},"filePathRelative":"posts/2026/2026-05-04-tienda-daw-web.md","excerpt":"<p>Como profesor del ciclo de DAW, me gusta que el alumnado trabaje con proyectos completos que les ayuden a entender cómo funcionan las cosas en el mundo real. No siempre es fácil, pero algo que sí puedo hacer es facilitarles ejemplos funcionales que cubran el currículo y les den una base sólida. Hoy os traigo <strong>WalaDaw</strong>, un marketplace en <strong>.NET</strong> que usa MVC, Razor Pages y Blazor Server.</p>\\n"}`),u={name:`2026-05-04-tienda-daw-web.md`};function d(s,l,u,d,f,p){let m=e(`Mermaid`);return i(),n(`div`,null,[l[0]||=t(`p`,null,[a(`Como profesor del ciclo de DAW, me gusta que el alumnado trabaje con proyectos completos que les ayuden a entender cómo funcionan las cosas en el mundo real. No siempre es fácil, pero algo que sí puedo hacer es facilitarles ejemplos funcionales que cubran el currículo y les den una base sólida. Hoy os traigo `),t(`strong`,null,`WalaDaw`),a(`, un marketplace en `),t(`strong`,null,`.NET`),a(` que usa MVC, Razor Pages y Blazor Server.`)],-1),c(` more `),l[1]||=o(`<div class="hint-container warning"><p class="hint-container-title">Una aclaración importante</p><p>Este proyecto es <strong>código de aprendizaje, no código de producción</strong>. No pretende ser un sistema real de comercio electrónico. Es un ejemplo didáctico que muestra cómo aplicar las tecnologías del currículo de DWES.</p><p><strong>Los fallos son intencionados</strong>: forman parte del aprendizaje. Un alumno que solo ve código &quot;perfecto&quot; no aprende a detectar problemas. En clase analizamos estos &quot;fallos&quot; y discutimos cómo mejorarían en un sistema real.</p></div><p>Imaginad a Víctor, un alumno de 2º DAW que en marzo está buscando empresa. Tiene su CV con las prácticas en empresa, pero necesita algo que le diferencie. Cuando muestra este proyecto en una entrevista técnica, no solo demuestra que sabe hacer un CRUD: demuestra que entiende <strong>arquitectura</strong>, <strong>testing</strong>, <strong>seguridad</strong> y <strong>tiempo real</strong>. Eso es lo que marca la diferencia.</p><p>En esta serie de post vamos a mostrar distintos proyectos que he desarrollado para mis clases, cada uno con un enfoque diferente. Este es el primero, y uno de los que más me gusta. ¡Vamos allá!</p><h2 id="aprendizaje-basado-en-proyectos-por-que-este-enfoque" tabindex="-1"><a class="header-anchor" href="#aprendizaje-basado-en-proyectos-por-que-este-enfoque"><span>Aprendizaje Basado en Proyectos: Por qué este enfoque</span></a></h2><p>Antes de nada, quiero explicar por qué hago esto. No soy fan de las clases donde explico teoría durante una hora y luego los alumnos hacen ejercicios sueltos. En DAW, eso no funciona. Un desarrollador web no aprende a hacer una tienda online resolviendo ejercicios de MVC sueltos. Aprende <strong>haciendo una tienda</strong>.</p><p>El <strong>Aprendizaje Basado en Proyectos (ABP)</strong> consiste en eso: aprender haciendo un proyecto real, con problemas reales, donde las tecnologías se usan porque son necesarias, no porque yo lo diga.</p><h3 id="mi-metodologia-en-clase" tabindex="-1"><a class="header-anchor" href="#mi-metodologia-en-clase"><span>Mi metodología en clase</span></a></h3><p>Así funciona una sesión típica conmigo:</p><ol><li><strong>Planteo un problema</strong>: &quot;Necesitamos que el usuario pueda filtrar productos por categoría sin recargar la página&quot;</li><li><strong>Exploramos soluciones</strong>: ¿Ajax? ¿JavaScript puro? ¿Blazor?</li><li><strong>Implementamos</strong>: Los alumnos trabajan en su copia del proyecto</li><li><strong>Revisamos</strong>: Analizamos qué ha funcionado y qué no</li><li><strong>Mejoramos</strong>: Entre todos buscamos una solución mejor</li></ol><p>No soy el que tiene todas las respuestas. Soy el que guía el proceso.</p><p><strong>Ciclo ABP en el aula:</strong></p>`,11),r(m,{code:``}),l[2]||=t(`p`,null,[t(`strong`,null,`Relación con el mundo profesional:`)],-1),r(m,{code:`eJx1zjEOgkAQBdDeU0xiqxZqYSwsFYw2aEcohmUWF4ddWFiNCbfiCFxMAsbY+Itfvfx8yeYpbmhrOAUT6HMIrxZjzFCDMLkB0uA0AuWFpQojmC/mu+aicsfYgBcG9FCV6loNCYHo2kSlJhqGvC9VjBZ67Yd7oiRGce8xA5VOFR/sj9hPHTKUjho4hmfKjMX+ha6VdjjCoar6xQQHkIp5O10v481mNROGjd1OpZQ/xv9r3kDdT5Y=`}),l[3]||=o(`<div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>El feedback en clase no es &quot;corregir errores&quot;. Es un diálogo donde analizamos qué ha pasado y por qué. Esto es exactamente lo que hacen las empresas en las revisiones de código. Los alumnos no solo aprenden a programar, aprenden a recibir feedback y a mejorar basándose en él.</p></div><h3 id="¿que-aporta-este-proyecto-como-ejemplo" tabindex="-1"><a class="header-anchor" href="#¿que-aporta-este-proyecto-como-ejemplo"><span>¿Qué aporta este proyecto como ejemplo?</span></a></h3><ol><li><p><strong>Es real, no artificial</strong>: No es un ejercicio fabricado artificialmente para aprender &quot;el tema 3&quot;. Es una aplicación que funciona, con datos que se persistentes, usuarios que se registran, carritos que funcionan.</p></li><li><p><strong>Cada tecnología tiene su momento</strong>: Cuando enseño MVC, el alumno ve por qué existe. Cuando llega Blazor, entiende qué problema resuelve. No son palabras vacías.</p></li><li><p><strong>Sirve como apuntes</strong>: El código del proyecto es el mejor material de estudio. No hace falta mis transparencias cuando tienes el proyecto completo con todo documentado en el repo.</p></li><li><p><strong>Pueden partir de aquí</strong>: Los alumnos pueden tomar este proyecto como base para sus propios trabajos. Les ahorro el &quot;desde cero&quot; y les reto a mejorarlo.</p></li><li><p><strong>Errores controlados</strong>: En un sistema real, un error puede tener consecuencias graves. En aprendizaje, los errores son oro. Este proyecto tiene fallos para que los detecten y aprendan a evitarlos.</p></li></ol><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>En FP no tenemos tiempo de hacer &quot;la teoría primero y la práctica después&quot;. El ABP funde ambas: aprendes la teoría cuando la necesitas para avanzar. Eso es lo que pasa en el mundo real, y eso es lo que preparamos.</p></div><h2 id="estructura-del-modulo-dwes" tabindex="-1"><a class="header-anchor" href="#estructura-del-modulo-dwes"><span>Estructura del módulo DWES</span></a></h2><p>En mi metodología para <strong>DWES (Desarrollo Web en Entornos Servidor)</strong>, divido el curso en dos grandes bloques:</p><ol><li><strong>Bloque de Servicios y APIs</strong>: Nos centramos en la lógica de negocio, el acceso a datos y los servicios RESTful.</li><li><strong>Bloque de Páginas Web Dinámicas</strong>: Recuperamos esa lógica y le damos vida mediante distintas tecnologías de renderizado.</li></ol><p><strong>WalaDaw</strong> es el puente entre ambos bloques, demostrando la versatilidad de <strong>.NET</strong> para dominar ambas etapas con un único lenguaje: C#, aunque se centra sobre todo en la segunda parte: la construcción de la interfaz con MVC, Razor Pages y Blazor Server, es decir, páginas web dinámicas con distintas tecnologías.</p><p>Si quieres ver el proyecto en acción, échale un vistazo al <strong><a href="https://tiendadawweb-netcore.onrender.com/" target="_blank" rel="noopener noreferrer">demo en Render</a></strong>. Y si te interesa el código, todo está en <strong><a href="https://github.com/joseluisgs/TiendaDawWeb-NetCore" target="_blank" rel="noopener noreferrer">GitHub</a></strong>.</p><h2 id="tecnologia-net" tabindex="-1"><a class="header-anchor" href="#tecnologia-net"><span>Tecnología: .NET</span></a></h2><p>Este proyecto usa <strong>.NET</strong>, la versión más reciente. ¿Por qué? Ofrece un ecosistema completo para desarrollo web, con herramientas de primera clase para cada capa:</p><ul><li><strong>Backend</strong>: ASP.NET Core con MVC, Razor Pages y Blazor Server</li><li><strong>Data Access</strong>: Entity Framework Core con SQLite In-Memory</li><li><strong>Testing</strong>: NUnit para unit e integración, bUnit para componentes Blazor, Playwright para E2E</li><li><strong>Contenerización</strong>: Docker para desarrollo y despliegue</li><li><strong>Internacionalización</strong>: Soporte para múltiples idiomas (i18n)</li></ul><h2 id="la-arquitectura-hibrida-mvc-razor-pages-y-blazor" tabindex="-1"><a class="header-anchor" href="#la-arquitectura-hibrida-mvc-razor-pages-y-blazor"><span>La Arquitectura Híbrida: MVC, Razor Pages y Blazor</span></a></h2><p>Lo que hace especial a este proyecto es su <strong>arquitectura híbrida</strong>: comparte el núcleo (servicios, repositorios, modelos) pero despliega tres aproximaciones distintas para la interfaz.</p><p>En clase, explico esto así: &quot;Imaginad que vais a construir una casa. Podéis usar ladrillo, bloques de hormigón o madera. Cada material tiene sus ventajas. Un buen arquitecto sabe cuándo usar cada uno. Aquí pasa igual: MVC, Razor y Blazor son herramientas diferentes para problemas diferentes.&quot;</p><h3 id="_1-asp-net-core-mvc-la-separacion-clasica" tabindex="-1"><a class="header-anchor" href="#_1-asp-net-core-mvc-la-separacion-clasica"><span>1. ASP.NET Core MVC: La separación clásica</span></a></h3><p>El patrón <strong>Model-View-Controller</strong> es la aproximación más conocida. Separa claramente la lógica de tres partes:</p><ul><li><strong>Model</strong>: Los datos y reglas de negocio</li><li><strong>View</strong>: Lo que ve el usuario (vistas Razor)</li><li><strong>Controller</strong>: Coordina todo, recibe peticiones y decide qué devolver</li></ul><p><strong>¿Cuándo usarlo?</strong> Cuando necesitas una estructura clara para aplicaciones grandes y empresariales. Enseña al alumno a pensar en términos de responsabilidades.</p><h3 id="_2-razor-pages-la-agilidad-centrada-en-pagina" tabindex="-1"><a class="header-anchor" href="#_2-razor-pages-la-agilidad-centrada-en-pagina"><span>2. Razor Pages: La agilidad centrada en página</span></a></h3><p><strong>Razor Pages</strong> agrupa la lógica y la vista en el mismo archivo. Es como si cada página fosse &quot;su propia mini-app&quot;.</p><p><strong>¿Cuándo usarlo?</strong> Para páginas más independientes (sobre nosotros, contacto, políticas). Reduce el &quot;boilerplate&quot; y es más rápido de desarrollar.</p><p>Mi truco: Uso Razor Pages para las páginas &quot;estáticas con dinamismo&quot; - las que apenas necesitan lógica pero necesitan datos (aviso legal con datos de empresa, página de contacto con horarios).</p><h3 id="_3-blazor-server-la-interactividad-en-tiempo-real" tabindex="-1"><a class="header-anchor" href="#_3-blazor-server-la-interactividad-en-tiempo-real"><span>3. Blazor Server: La interactividad en tiempo real</span></a></h3><p>Aquí está el salto cualitativo. <strong>Blazor Server</strong> permite escribir componentes interactivos <strong>todo en C#</strong> - nada de JavaScript. Usa <strong>SignalR</strong> para comunicación en tiempo real entre el navegador y el servidor.</p><p><strong>¿Qué aporta?</strong></p><ul><li>Filtros de productos que se actualizan sin recargar</li><li>Dashboard de admin con gráficos en vivo</li><li>Notificaciones push del servidor</li></ul><p>La primera vez que pongo un ejemplo de Blazor en clase, los alumnos se quedan mirando. &quot;¿Esto es JavaScript?&quot; - &quot;No, es C#. El servidor está ejecutando código C# en el navegador del usuario&quot;. Hay un momento de confusión, luego de interés, luego de &quot;¿esto funciona de verdad?&quot;. Y sí, funciona.</p><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>Blazor no es &quot;JavaScript hecho en C#&quot;. Es una forma diferente de pensar: el servidor mantiene una conexión con el navegador y envía actualizaciones. Eso tiene implicaciones importantes en seguridad y rendimiento.</p></div>`,29),r(m,{code:``}),l[4]||=o(`<h2 id="comparativa-¿cuando-usar-cada-enfoque" tabindex="-1"><a class="header-anchor" href="#comparativa-¿cuando-usar-cada-enfoque"><span>Comparativa: ¿Cuándo usar cada enfoque?</span></a></h2><table><thead><tr><th>Característica</th><th>MVC</th><th>Razor Pages</th><th>Blazor Server</th></tr></thead><tbody><tr><td><strong>Paradigma</strong></td><td>Separación estricta</td><td>Página como unidad</td><td>Componentes</td></tr><tr><td><strong>Curva aprendizaje</strong></td><td>Media</td><td>Baja</td><td>Media</td></tr><tr><td><strong>Estado</strong></td><td>Sin estado</td><td>Sin estado</td><td>Con estado (circuito)</td></tr><tr><td><strong>Interactividad</strong></td><td>JavaScript</td><td>JavaScript/AJAX</td><td>C# nativo</td></tr><tr><td><strong>Rendimiento inicial</strong></td><td>Alto</td><td>Alto</td><td>Medio</td></tr><tr><td><strong>Uso típico</strong></td><td>Apps grandes</td><td>CMS, páginas</td><td>Apps reactivas</td></tr></tbody></table><h2 id="testing-la-piramide-completa" tabindex="-1"><a class="header-anchor" href="#testing-la-piramide-completa"><span>Testing: La pirámide completa</span></a></h2><p>Un proyecto &quot;de referencia&quot; no puede fallar. La suite de pruebas incluye:</p><table><thead><tr><th>Nivel</th><th>Tipo</th><th>Herramienta</th></tr></thead><tbody><tr><td><strong>1</strong></td><td>Unit Tests</td><td>NUnit</td></tr><tr><td><strong>2</strong></td><td>Integration</td><td>NUnit + SQLite</td></tr><tr><td><strong>3</strong></td><td>Component</td><td>bUnit (para Blazor)</td></tr><tr><td><strong>4</strong></td><td>E2E</td><td>Playwright</td></tr></tbody></table><h3 id="¿que-es-playwright-y-por-que-es-importante" tabindex="-1"><a class="header-anchor" href="#¿que-es-playwright-y-por-que-es-importante"><span>¿Qué es Playwright y por qué es importante?</span></a></h3><p>En clase explico Playwright así: &quot;Unit tests prueban funciones sueltas. Los tests E2E prueban como un usuario real: abre el navegador, hace clic, navega, rellena formularios.&quot; Playwright hace exactamente eso: automatiza un navegador real (Chrome, Firefox, Safari) y simula interacciones de usuario.</p><p><strong>¿Por qué es importante?</strong></p><ul><li><strong>Prueba lo que el usuario ve</strong>: No basta con que el código funcione; el usuario debe poder usarlo. Playwright detecta problemas visuales y de interacción que los tests unitarios no ven.</li><li><strong>Detecta regresiones</strong>: Si cambias algo y rompes algo, Playwright lo detecta antes de que el usuario lo vea.</li><li><strong>Automatización real</strong>: Es lo mismo que hacen las herramientas de integración continua (CI/CD). Si funciona en Playwright, funciona en producción.</li></ul><p><strong>En el proyecto:</strong></p><ul><li>Tests de login: ¿el usuario puede iniciar sesión?</li><li>Tests de navegación: ¿los menús funcionan?</li><li>Tests de carrito: ¿se añaden productos correctamente?</li></ul><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>Enseñar testing no es solo &quot;saber escribir tests&quot;. Es entender la pirámide: muchos tests pequeños y rápidos (unit), algunos de integración, y muy pocos E2E (lentos). Los unit tests se ejecutan en milisegundos, los E2E pueden tardar minutos. Por eso la pirámide tiene muchos abajo y pocos arriba.</p></div><h2 id="seguridad-empresarial" tabindex="-1"><a class="header-anchor" href="#seguridad-empresarial"><span>Seguridad Empresarial</span></a></h2><p>El proyecto implementa <strong>ASP.NET Core Identity</strong> con:</p><ul><li>Autenticación con cookies segura</li><li>Roles: ADMIN, USER, MODERADOR</li><li>Claims para información adicional del usuario</li><li>Password hashing automático</li><li>Protección CSRF en todos los formularios</li><li>Authorization a nivel de controlador y acción</li><li>Security headers (HSTS, X-Frame-Options)</li></ul><h3 id="por-que-la-seguridad-es-clave-en-dwes" tabindex="-1"><a class="header-anchor" href="#por-que-la-seguridad-es-clave-en-dwes"><span>Por qué la seguridad es clave en DWES</span></a></h3><p>En desarrollo web, la seguridad no es opcional. Cualquier aplicación que maneje datos de usuarios necesita protección. Pero en FP suele costar vender esto. &quot;¿Por qué necesito seguridad si hago una tienda de libros?&quot; - Les dejo probar a hacer un panel de admin sin protección y en 5 minutos tienen un desastre: cualquier usuario puede entrar, borrar lo que quiere, ver datos de otros. Entonces lo entienden.</p><h3 id="roles-vs-claims-¿cuando-usar-cada-uno" tabindex="-1"><a class="header-anchor" href="#roles-vs-claims-¿cuando-usar-cada-uno"><span>Roles vs Claims: ¿cuándo usar cada uno?</span></a></h3><p>En clase explico la diferencia así: los <strong>roles</strong> son como el carnet de identidad (admin, usuario, moderador), y los <strong>claims</strong> son como los datos de ese carnet (nombre, email, preferencias).</p><ul><li><strong>Roles</strong>: Para control de acceso grosso (&quot;solo los admins pueden entrar aquí&quot;)</li><li><strong>Claims</strong>: Para información específica (&quot;mostrar solo los pedidos de este usuario&quot;)</li></ul><p>En la práctica se usan ambos: <code>[Authorize(Roles = &quot;ADMIN&quot;)]</code> para proteger rutas, y claims para personalizar la experiencia.</p><h3 id="password-hashing" tabindex="-1"><a class="header-anchor" href="#password-hashing"><span>Password hashing</span></a></h3><p>Identity usa <strong>BCrypt</strong> por defecto, que incluye salt automático. En clase explico: no es lo mismo que cifrar. El hash es unidireccional: puedes convertir &quot;password123&quot; en un hash, pero no puedes recuperar &quot;password123&quot; a partir del hash. Se guarda el hash, nunca la contraseña. Cuando el usuario inicia sesión, se hashea lo que escribe y se compara con el hash guardado. Si coincide, acceso concedido.</p><p>Además, BCrypt es adaptive: permite aumentar el coste computacional con el tiempo. Esto significa que un ataque de fuerza bruta se vuelve cada vez más lento y costoso. Los sitios que usan BCrypt hace 10 años pueden aumentar el &quot;work factor&quot; y seguir protegidos.</p><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>La seguridad en FP suele parecer &quot;aburrida&quot;. Pero este proyecto hace que sea tangible: cada feature de Identity protege algo real. Los alumnos ven el resultado. &quot;Si no pongo [Authorize], cualquiera entra al dashboard&quot; - y lo ven funcionando.</p></div><h2 id="persistencia-con-sqlite-in-memory" tabindex="-1"><a class="header-anchor" href="#persistencia-con-sqlite-in-memory"><span>Persistencia con SQLite In-Memory</span></a></h2><p>Usamos <strong>SQLite In-Memory</strong> para desarrollo y testing:</p><ul><li>Sin instalación: no necesitas MySQL ni PostgreSQL</li><li>Base de datos volátil: ideal para demos y tests</li><li>Todo en RAM: rendimiento máximo</li><li>Transacciones reales con Entity Framework Core</li></ul><h2 id="docker-y-despliegue" tabindex="-1"><a class="header-anchor" href="#docker-y-despliegue"><span>Docker y Despliegue</span></a></h2><p>Todo el sistema está <strong>contenedorizado</strong> con Docker:</p><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">docker-compose</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> up</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -d</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> --build</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="¿por-que-es-importante-el-despliegue-en-fp" tabindex="-1"><a class="header-anchor" href="#¿por-que-es-importante-el-despliegue-en-fp"><span>¿Por qué es importante el despliegue en FP?</span></a></h3><p>En clase insisto: &quot;Un desarrollador que solo sabe programar pero no sabe desplegar está incompleto.&quot; El despliegue es donde el código se convierte en producto. Los alumnos aprenden que el desarrollo no termina cuando el código funciona en su máquina.</p><p><strong>El proyecto incluye:</strong></p><ul><li><strong>Docker</strong>: Contenedores para desarrollo y producción</li><li><strong>GitHub</strong>: Todo el código está en un repositorio público, con historial de cambios, ramas e incidencias</li><li><strong>Render</strong>: Despliegue automático y continuo</li></ul><h3 id="github-mas-que-un-lugar-para-el-codigo" tabindex="-1"><a class="header-anchor" href="#github-mas-que-un-lugar-para-el-codigo"><span>GitHub: Más que un lugar para el código</span></a></h3><p>El repositorio de GitHub no es solo donde se guarda el código. Es:</p><ul><li><strong>Historial de cambios</strong>: Cada commit cuenta una historia de lo que se ha hecho</li><li><strong>Colaboración</strong>: Los alumnos aprenden a trabajar en equipo con ramas y pull requests</li><li><strong>Documentación</strong>: El README, los documentos en la carpeta doc/, todo está versionado</li><li><strong>Portfolio</strong>: Cuando buscan trabajo, tienen algo tangible que mostrar</li></ul><p>El proyecto está desplegado en <strong><a href="https://tiendadawweb-netcore.onrender.com/" target="_blank" rel="noopener noreferrer">Render</a></strong> y el código disponible en <strong><a href="https://github.com/joseluisgs/TiendaDawWeb-NetCore" target="_blank" rel="noopener noreferrer">GitHub</a></strong>.</p><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>En clase les digo: &quot;Tu GitHub es tu CV técnico. Un repositorio ordenado, con commits claros y buena documentación dice mucho de ti como profesional.&quot;</p></div><h2 id="ci-cd-con-github-actions" tabindex="-1"><a class="header-anchor" href="#ci-cd-con-github-actions"><span>CI/CD con GitHub Actions</span></a></h2><p>Cada vez que alguien hace un push a la rama principal, pasa esto:</p><ol><li><strong>Se ejecutan los tests</strong>: NUnit, bUnit y Playwright</li><li><strong>Si pasan</strong>: Se construye la aplicación</li><li><strong>Si la build funciona</strong>: Se despliega automáticamente en Render</li></ol><p>Esto cierra el ciclo de vida profesional del software. Los alumnos ven cómo se trabaja en el mundo real: el código no se sube &quot;a mano&quot;, se automatiza todo.</p><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>Enseñar CI/CD desde el principio cambia la mentalidad del alumno. Ya no es &quot;escribo código y lo subo&quot;, sino &quot;escribo código, pasan los tests, y se despliega solo&quot;.</p></div><h2 id="orientaciones-pedagogicas-del-curriculo" tabindex="-1"><a class="header-anchor" href="#orientaciones-pedagogicas-del-curriculo"><span>Orientaciones Pedagógicas del Currículo</span></a></h2><p>El currículo del módulo 0613 define varias <strong>líneas de actuación</strong> para el proceso de enseñanza-aprendizaje. Aquí te explico cómo este proyecto cubre cada una:</p><h3 id="_1-analisis-de-los-metodos-de-generacion-dinamica-de-documentos-web" tabindex="-1"><a class="header-anchor" href="#_1-analisis-de-los-metodos-de-generacion-dinamica-de-documentos-web"><span>1. Análisis de los métodos de generación dinámica de documentos web</span></a></h3><p>El proyecto muestra <strong>tres formas distintas</strong> de generar HTML dinámico:</p><ul><li><strong>ASP.NET Core MVC</strong>: El servidor genera HTML ejecutando controladores y devolviendo vistas</li><li><strong>Razor Pages</strong>: Cada página es una unidad que combina lógica y presentación</li><li><strong>Blazor Server</strong>: El servidor genera componentes que se actualizan en tiempo real</li></ul><p>En clase comparamos los tres métodos y analizamos cómo cada uno produce HTML diferente según los datos y el contexto.</p><h3 id="_2-integracion-del-lenguaje-de-marcas-con-el-codigo-ejecutable-en-el-servidor-web" tabindex="-1"><a class="header-anchor" href="#_2-integracion-del-lenguaje-de-marcas-con-el-codigo-ejecutable-en-el-servidor-web"><span>2. Integración del lenguaje de marcas con el código ejecutable en el servidor web</span></a></h3><p>Las vistas Razor (.cshtml) son el ejemplo perfecto: HTML con código C# embebido. Los alumnos ven cómo las etiquetas <code>@Model</code>, <code>@if</code>, <code>@foreach</code>, <code>@inject</code> mezclan el lenguaje de marcas con la lógica de programación. No es teoría: es código que ejecutan y ven funcionar.</p><h3 id="_3-analisis-diferenciacion-y-clasificacion-de-caracteristicas-y-funcionalidades-de-entornos-y-lenguajes-de-programacion-de-servidores-web" tabindex="-1"><a class="header-anchor" href="#_3-analisis-diferenciacion-y-clasificacion-de-caracteristicas-y-funcionalidades-de-entornos-y-lenguajes-de-programacion-de-servidores-web"><span>3. Análisis, diferenciación y clasificación de características y funcionalidades de entornos y lenguajes de programación de servidores web</span></a></h3><p>El proyecto usa <strong>.NET 10 con C#</strong> como único lenguaje para servidor y cliente (Blazor). Los alumnos ven que pueden hacer todo - desde controladores hasta componentes interactivos - con el mismo lenguaje. Esto les ayuda a entender la ventajas de un ecosistema integrado.</p><h3 id="_4-utilizacion-de-caracteristicas-y-funcionalidades-especificas-de-los-lenguajes-de-programacion-seleccionados" tabindex="-1"><a class="header-anchor" href="#_4-utilizacion-de-caracteristicas-y-funcionalidades-especificas-de-los-lenguajes-de-programacion-seleccionados"><span>4. Utilización de características y funcionalidades específicas de los lenguajes de programación seleccionados</span></a></h3><p>C# en este proyecto usa características modernas: sintaxis moderna con type safety, LINQ para consultas, async/await para operaciones asíncronas, patrón MVC con inyección de dependencias. Los alumnos no solo aprenden la teoría, usan estas características en código real.</p><h3 id="_5-modificacion-del-codigo-existente-y-analisis-de-datos-en-soluciones-web-heterogeneas-para-su-adaptacion-a-entornos-especificos" tabindex="-1"><a class="header-anchor" href="#_5-modificacion-del-codigo-existente-y-analisis-de-datos-en-soluciones-web-heterogeneas-para-su-adaptacion-a-entornos-especificos"><span>5. Modificación del código existente y análisis de datos en soluciones web heterogéneas para su adaptación a entornos específicos</span></a></h3><p>El proyecto está diseñado para que los alumnos puedan partir de él y modificarlo. No es &quot;código cerrado&quot;: pueden cambiar funcionalidades, añadir características, adaptar el proyecto a sus necesidades. Les retamos a mejorar lo que ya existe.</p><h3 id="_6-analisis-y-utilizacion-de-funcionalidades-aportadas-por-frameworks-de-programacion-web-en-entorno-servidor" tabindex="-1"><a class="header-anchor" href="#_6-analisis-y-utilizacion-de-funcionalidades-aportadas-por-frameworks-de-programacion-web-en-entorno-servidor"><span>6. Análisis y utilización de funcionalidades aportadas por frameworks de programación web en entorno servidor</span></a></h3><p>El proyecto usa <strong>ASP.NET Core</strong> como framework principal, pero también incluye:</p><ul><li><strong>Entity Framework Core</strong> para acceso a datos</li><li><strong>ASP.NET Core Identity</strong> para seguridad</li><li><strong>SignalR</strong> para tiempo real</li></ul><p>Los alumnos analizan qué aporta cada framework y cuándo usarlo.</p><h3 id="_7-utilizacion-de-frameworks-para-incorporar-interactividad-a-los-documentos-web-generados-de-forma-dinamica" tabindex="-1"><a class="header-anchor" href="#_7-utilizacion-de-frameworks-para-incorporar-interactividad-a-los-documentos-web-generados-de-forma-dinamica"><span>7. Utilización de frameworks para incorporar interactividad a los documentos web generados de forma dinámica</span></a></h3><p>Aquí es donde <strong>Blazor Server</strong> brilla. No es necesario escribir JavaScript para tener interactividad: los componentes Blazor actualizan el contenido sin recargar la página. Los filtros de productos, el carrito reactivo, el dashboard con gráficos en tiempo real son ejemplos de esto.</p><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>Estas líneas de actuación no son apartados teóricos. Cada una se trabaja en clase mientras los alunos trabajan en el proyecto. No aprenden &quot;sobre&quot; interactividad: la implementan con Blazor.</p></div><hr><h2 id="analisis-curricular-modulo-0613" tabindex="-1"><a class="header-anchor" href="#analisis-curricular-modulo-0613"><span>Análisis Curricular (Módulo 0613)</span></a></h2><p>El proyecto está diseñado para cubrir el 100% del currículo. Pero, ¿qué significa esto en la práctica? Aquí te explico cada resultado de aprendizaje y cómo se trabaja en el proyecto.</p><hr><h3 id="ra1-selecciona-las-arquitecturas-y-tecnologias-de-programacion-web-en-entorno-servidor-analizando-sus-capacidades-y-caracteristicas-propias" tabindex="-1"><a class="header-anchor" href="#ra1-selecciona-las-arquitecturas-y-tecnologias-de-programacion-web-en-entorno-servidor-analizando-sus-capacidades-y-caracteristicas-propias"><span>RA1: Selecciona las arquitecturas y tecnologías de programación web en entorno servidor, analizando sus capacidades y características propias.</span></a></h3><p>Este resultado aborda la comprensión de cómo funcionan las arquitecturas web. En clase, antes de escribir código, dedico tiempo a explicar &quot;qué pasa cuando escribes una URL y le das a enter&quot;. Este proyecto permite ver todo eso en acción.</p><table><thead><tr><th>CE</th><th>Descripción</th><th>Cómo se trabaja en WalaDaw</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>Se han caracterizado y diferenciado los modelos de ejecución de código en el servidor y en el cliente web</td><td>Las vistas Razor se ejecutan en servidor (servidor web Kestrel), los componentes Blazor también pero con SignalR, y el JavaScript resultante se ejecuta en navegador. Los alumnos ven la diferencia.</td></tr><tr><td><strong>b</strong></td><td>Se han reconocido las ventajas que proporciona la generación dinámica de páginas</td><td>Las páginas de productos muestran datos de la base de datos en tiempo real. No son HTML estático, se genera cada vez según los datos.</td></tr><tr><td><strong>c</strong></td><td>Se han identificado los mecanismos de ejecución de código en los servidores web</td><td>El proyecto usa Kestrel como servidor. Los controladores reciben peticiones HTTP, procesan y devuelven respuestas.</td></tr><tr><td><strong>d</strong></td><td>Se han reconocido las funcionalidades que aportan los servidores de aplicaciones y su integración con los servidores web</td><td>El proyecto se ejecuta sobre ASP.NET Core, que hace de servidor de aplicaciones integrándose con Kestrel.</td></tr><tr><td><strong>e</strong></td><td>Se han identificado y caracterizado los principales lenguajes y tecnologías relacionados con la programación web en entorno servidor</td><td>C# como lenguaje principal, Razor como motor de plantillas, Blazor como framework.</td></tr><tr><td><strong>f</strong></td><td>Se han verificado los mecanismos de integración de los lenguajes de marcas con los lenguajes de programación en entorno servidor</td><td>Las vistas Razor (HTML con código C# embebido) son el ejemplo perfecto. Etiquetas @model, @inject, @using.</td></tr><tr><td><strong>g</strong></td><td>Se han reconocido y evaluado las herramientas y frameworks de programación en entorno servidor</td><td>Visual Studio, dotnet CLI, GitHub Actions, Docker. Las herramientas reales del mercado.</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>Este RA se cubre con la propia arquitectura del proyecto. Los alumnos pueden comparar el código fuente de una página (ver &gt; código fuente) con las vistas Razor del proyecto, viendo la diferencia entre lo que se ejecuta en servidor y lo que llega al navegador. La arquitectura híbrida (MVC + Razor Pages + Blazor) permite ver distintos modelos de ejecución.</p></div><hr><h3 id="ra2-escribe-sentencias-ejecutables-por-un-servidor-web-reconociendo-y-aplicando-procedimientos-de-integracion-del-codigo-en-lenguajes-de-marcas" tabindex="-1"><a class="header-anchor" href="#ra2-escribe-sentencias-ejecutables-por-un-servidor-web-reconociendo-y-aplicando-procedimientos-de-integracion-del-codigo-en-lenguajes-de-marcas"><span>RA2: Escribe sentencias ejecutables por un servidor web reconociendo y aplicando procedimientos de integración del código en lenguajes de marcas.</span></a></h3><p>Aquí se trabaja la sintaxis básica de Razor: cómo escribir código C# dentro de HTML.</p><table><thead><tr><th>CE</th><th>Descripción</th><th>Cómo se trabaja en WalaDaw</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>Se han reconocido los mecanismos de generación de páginas web a partir de lenguajes de marcas con código embebido</td><td>Todas las vistas Razor (.cshtml) son exactamente esto: HTML con código C# embebido.</td></tr><tr><td><strong>b</strong></td><td>Se han identificado las principales tecnologías asociadas</td><td>Sintaxis Razor, Tag Helpers, componentes de vista.</td></tr><tr><td><strong>c</strong></td><td>Se han utilizado etiquetas para la inclusión de código en el lenguaje de marcas</td><td>Las etiquetas Razor como <code>@{}</code>, <code>@Model</code>, <code>@{}</code>, <code>@Html</code>.</td></tr><tr><td><strong>d</strong></td><td>Se ha reconocido la sintaxis del lenguaje de programación que se ha de utilizar</td><td>Se usa C# dentro de las vistas. Los alumnos practican la sintaxis continuamente.</td></tr><tr><td><strong>e</strong></td><td>Se han escrito sentencias simples y se han comprobado sus efectos en el documento resultante</td><td>Mostrar variables (<code>@producto.Nombre</code>), condiciones (<code>@if</code>), bucles (<code>@foreach</code>).</td></tr><tr><td><strong>f</strong></td><td>Se han utilizado directivas para modificar el comportamiento predeterminado</td><td><code>@model</code>, <code>@using</code>, <code>@namespace</code>, <code>_ViewImports.cshtml</code>.</td></tr><tr><td><strong>g</strong></td><td>Se han utilizado los distintos tipos de variables y operadores disponibles en el lenguaje</td><td>Variables de ViewData, ViewBag, Model, vistas fuertemente tipadas.</td></tr><tr><td><strong>h</strong></td><td>Se han identificado los ámbitos de utilización de las variables</td><td>Diferencia entre ViewData (por petición), TempData (entre peticiones), ViewBag (dinámico), Model (tipado).</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>El proyecto cubre este RA con ejemplos progresivos: desde mostrar variables simples (<code>@Model.Nombre</code>) hasta condiciones (<code>@if</code>) y bucles (<code>@foreach</code>). Todas las vistas del proyecto usan distintas combinaciones de estas estructuras, sirviendo como referencia práctica de la sintaxis Razor.</p></div><hr><h3 id="ra3-escribe-bloques-de-sentencias-embebidos-en-lenguajes-de-marcas-seleccionando-y-utilizando-las-estructuras-de-programacion" tabindex="-1"><a class="header-anchor" href="#ra3-escribe-bloques-de-sentencias-embebidos-en-lenguajes-de-marcas-seleccionando-y-utilizando-las-estructuras-de-programacion"><span>RA3: Escribe bloques de sentencias embebidos en lenguajes de marcas, seleccionando y utilizando las estructuras de programación.</span></a></h3><p>Programación básica: condicionales, bucles, funciones, formularios.</p><table><thead><tr><th>CE</th><th>Descripción</th><th>Cómo se trabaja en WalaDaw</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>Se han utilizado mecanismos de decisión en la creación de bloques de sentencias</td><td><code>@if</code>, <code>@else</code>, <code>@switch</code> en todas las vistas.</td></tr><tr><td><strong>b</strong></td><td>Se han utilizado bucles y se ha verificado su funcionamiento</td><td><code>@foreach</code> para listar productos, categorías, pedidos.</td></tr><tr><td><strong>c</strong></td><td>Se han utilizado matrices (arrays) para almacenar y recuperar conjuntos de datos</td><td>Listas de productos, colecciones de categorías.</td></tr><tr><td><strong>d</strong></td><td>Se han creado y utilizado funciones</td><td>Métodos en controladores, funciones en servicios, métodos en componentes Blazor.</td></tr><tr><td><strong>e</strong></td><td>Se han utilizado formularios web para interactuar con el usuario del navegador web</td><td>Formularios de login, registro, añadir producto, finalizar compra.</td></tr><tr><td><strong>f</strong></td><td>Se han empleado métodos para recuperar la información introducida en el formulario</td><td>Enlace de modelo en controladores, <code>[BindProperty]</code> en Razor Pages.</td></tr><tr><td><strong>g</strong></td><td>Se han añadido comentarios al código</td><td>El código incluye comentarios explicativos, y en la documentación se explica el por qué.</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>El proyecto usa constantemente bloques de decisión (<code>@if</code>, <code>@else</code>, <code>@switch</code>) y bucles (<code>@foreach</code>) en todas las vistas. Los listados de productos, las condiciones de visibilidad según el rol del usuario, y los formularios dinámicos son ejemplos concretos de este RA en acción.</p></div><hr><h3 id="ra4-desarrolla-aplicaciones-web-embebidas-en-lenguajes-de-marcas-analizando-e-incorporando-funcionalidades-segun-especificaciones" tabindex="-1"><a class="header-anchor" href="#ra4-desarrolla-aplicaciones-web-embebidas-en-lenguajes-de-marcas-analizando-e-incorporando-funcionalidades-segun-especificaciones"><span>RA4: Desarrolla aplicaciones web embebidas en lenguajes de marcas analizando e incorporando funcionalidades según especificaciones.</span></a></h3><p>Aquí entran sesiones, cookies, autentificación y estado.</p><table><thead><tr><th>CE</th><th>Descripción</th><th>Cómo se trabaja en WalaDaw</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>Se han identificado los mecanismos disponibles para el mantenimiento de la información que concierne a un cliente web concreto y se han señalado sus ventajas</td><td>El carrito de la compra necesita recordar qué productos ha seleccionado el usuario. Se usa sesión.</td></tr><tr><td><strong>b</strong></td><td>Se han utilizado mecanismos para mantener el estado de las aplicaciones web</td><td>Sesiones ASP.NET Core para el carrito, TempData para mensajes entre peticiones.</td></tr><tr><td><strong>c</strong></td><td>Se han utilizado mecanismos para almacenar información en el cliente web y para recuperar su contenido</td><td>Cookies para preferencias de idioma, localStorage para consentimientos de cookies.</td></tr><tr><td><strong>d</strong></td><td>Se han identificado y caracterizado los mecanismos disponibles para la autentificación de usuarios</td><td>ASP.NET Core Identity con cookies de autentificación.</td></tr><tr><td><strong>e</strong></td><td>Se han escrito aplicaciones que integren mecanismos de autentificación de usuarios</td><td>Todo el sistema de registro/login, protección de rutas con <code>[Authorize]</code>.</td></tr><tr><td><strong>f</strong></td><td>Se han utilizado herramientas y entornos para facilitar la programación, prueba y depuración del código</td><td>Visual Studio depurador, herramientas de desarrollo del navegador, logs con Serilog.</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>El proyecto implementa todo el manejo de estado: sesiones para el carrito de compra, cookies para preferencias de idioma, TempData para mensajes entre peticiones, y ASP.NET Core Identity para autentificación. Los alumnos pueden ver cómo funciona cada mecanismo en un caso real y tangible.</p></div><hr><h3 id="ra5-desarrolla-aplicaciones-web-identificando-y-aplicando-mecanismos-para-separar-el-codigo-de-presentacion-de-la-logica-de-negocio" tabindex="-1"><a class="header-anchor" href="#ra5-desarrolla-aplicaciones-web-identificando-y-aplicando-mecanismos-para-separar-el-codigo-de-presentacion-de-la-logica-de-negocio"><span>RA5: Desarrolla aplicaciones web identificando y aplicando mecanismos para separar el código de presentación de la lógica de negocio.</span></a></h3><p>El corazón del módulo: el patrón MVC, inyección de dependencias, testing.</p><table><thead><tr><th>CE</th><th>Descripción</th><th>Cómo se trabaja en WalaDaw</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>Se han identificado las ventajas de separar la lógica de negocio de los aspectos de presentación de la aplicación</td><td>El proyecto demuestra esto: servicios separados de las vistas, lógica de negocio en capa de servicios.</td></tr><tr><td><strong>b</strong></td><td>Se han analizado y utilizado mecanismos y frameworks que permiten realizar esta separación y sus características principales</td><td>El propio ASP.NET Core MVC con su flujo de procesamiento, inyección de dependencias nativa.</td></tr><tr><td><strong>c</strong></td><td>Se han utilizado objetos y controles en el servidor para generar el aspecto visual de la aplicación web en el cliente</td><td>Modelos de vista, Tag Helpers personalizados, Componentes de vista.</td></tr><tr><td><strong>d</strong></td><td>Se han utilizado formularios generados de forma dinámica para responder a los eventos de la aplicación web</td><td>Formularios que se generan según datos de la base de datos, validación dinámica.</td></tr><tr><td><strong>e</strong></td><td>Se han identificado y aplicado los parámetros relativos a la configuración de la aplicación web</td><td>appsettings.json, configuración de Identity, configuración de servicios en Startup/Program.cs.</td></tr><tr><td><strong>f</strong></td><td>Se han escrito aplicaciones web con mantenimiento de estado y separación de la lógica de negocio</td><td>El proyecto completo: estado gestionado por sesiones, lógica en servicios separados.</td></tr><tr><td><strong>g</strong></td><td>Se han aplicado los principios y patrones de diseño de la programación orientada a objetos</td><td>Clases, interfaces, herencia, encapsulamiento. Servicios que implementan interfaces.</td></tr><tr><td><strong>h</strong></td><td>Se ha probado y documentado el código</td><td>El proyecto incluye tests unitarios con NUnit para lógica de negocio, tests de integración con SQLite In-Memory, y tests E2E con Playwright. Además, el código usa XMLDoc en todos los métodos públicos: resúmenes (summary) que explican qué hace cada método, parámetros y valor de retorno. Esto permite generar documentación automática y aparece en IntelliSense. La documentación adicional está en la carpeta doc/.</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>El proyecto cubre este RA con separación total de responsabilidades: la lógica de negocio está en servicios separados, las vistas solo presentan datos, y todo se conecta mediante inyección de dependencias. Los tests unitarios con NUnit prueban cada servicio de forma aislada, los tests E2E con Playwright prueban flujos completos, y XMLDoc documenta cada método público. Esto es exactamente lo que se espera en un proyecto profesional.</p></div><hr><h3 id="ra6-desarrolla-aplicaciones-web-de-acceso-a-almacenes-de-datos-aplicando-medidas-para-mantener-la-seguridad-y-la-integridad-de-la-informacion" tabindex="-1"><a class="header-anchor" href="#ra6-desarrolla-aplicaciones-web-de-acceso-a-almacenes-de-datos-aplicando-medidas-para-mantener-la-seguridad-y-la-integridad-de-la-informacion"><span>RA6: Desarrolla aplicaciones web de acceso a almacenes de datos, aplicando medidas para mantener la seguridad y la integridad de la información.</span></a></h3><p>Entity Framework Core, consultas, transacciones, seguridad.</p><table><thead><tr><th>CE</th><th>Descripción</th><th>Cómo se trabaja en WalaDaw</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>Se han analizado las tecnologías que permiten el acceso mediante programación a la información disponible en almacenes de datos</td><td>Entity Framework Core como ORM, SQLite como base de datos.</td></tr><tr><td><strong>b</strong></td><td>Se han creado aplicaciones que establezcan conexiones con bases de datos</td><td>DbContext configurado, connection strings, contexto de base de datos.</td></tr><tr><td><strong>c</strong></td><td>Se ha recuperado información almacenada en bases de datos</td><td>Consultas LINQ, Include para relaciones, filtros where.</td></tr><tr><td><strong>d</strong></td><td>Se ha publicado en aplicaciones web la información recuperada</td><td>Las vistas muestran productos, categorías, pedidos desde la base de datos.</td></tr><tr><td><strong>e</strong></td><td>Se han utilizado conjuntos de datos para almacenar la información</td><td>Entity Framework carga entidades, LINQ procesa resultados.</td></tr><tr><td><strong>f</strong></td><td>Se han creado aplicaciones web que permitan la actualización y la eliminación de información disponible en una base de datos</td><td>CRUD completo: Create, Read, Update, Delete de productos, categorías, usuarios.</td></tr><tr><td><strong>g</strong></td><td>Se han probado y documentado las aplicaciones web</td><td>Tests de integración con SQLite In-Memory, documentación de Entity Framework.</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>Este RA se trabaja con Entity Framework Core y SQLite In-Memory. Los alumnos aprenden a hacer consultas LINQ (filtros, ordenaciones, agrupaciones), relaciones entre entidades (uno a muchos, muchos a muchos), y transacciones. El dashboard de admin con gráficos es un ejemplo práctico de análisis de datos (Big Data a pequeña escala).</p></div><hr><h3 id="ra7-desarrolla-servicios-web-reutilizables-y-accesibles-mediante-protocolos-web-verificando-su-funcionamiento" tabindex="-1"><a class="header-anchor" href="#ra7-desarrolla-servicios-web-reutilizables-y-accesibles-mediante-protocolos-web-verificando-su-funcionamiento"><span>RA7: Desarrolla servicios web reutilizables y accesibles mediante protocolos web, verificando su funcionamiento.</span></a></h3><blockquote><p>⚠️ <strong>Este resultado de aprendizaje NO se cubre en este proyecto</strong>.</p></blockquote><p>Crear y consumir APIs RESTful es tan importante que merece su propio proyecto dedicado. WalaDaw se centra en la parte de &quot;páginas web dinámicas&quot;, pero los servicios web los trataremos en otro proyecto: <strong>TiendaDawApi-NetCore</strong> (<a href="https://github.com/joseluisgs/TiendaDawApi-NetCore" target="_blank" rel="noopener noreferrer">GitHub</a>), en ellos nos centramos en el desarrollo de servicios, apis RESTful, WebSockets, GraphQL, autenticación con JWT, documentación con Swagger, y testing de APIs, etc.</p><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>¿Por qué un proyecto dedicado a APIs? Porque en el mercado actual, las APIs son fundamentales. Un desarrollador que sabe hacer páginas pero no sabe crear y consumir APIs está a medias. Por eso dedicamos un proyecto entero a esto. Desde mi punto de vista, es tan importante como el desarrollo de páginas web dinámicas o más en el contexto actual del desarrollo web.</p></div><hr><h3 id="ra8-genera-paginas-web-dinamicas-analizando-y-utilizando-tecnologias-y-frameworks-del-servidor-web-que-anadan-codigo-al-lenguaje-de-marcas" tabindex="-1"><a class="header-anchor" href="#ra8-genera-paginas-web-dinamicas-analizando-y-utilizando-tecnologias-y-frameworks-del-servidor-web-que-anadan-codigo-al-lenguaje-de-marcas"><span>RA8: Genera páginas web dinámicas analizando y utilizando tecnologías y frameworks del servidor web que añadan código al lenguaje de marcas.</span></a></h3><p>Este resultado se trabaja con las tres tecnologías del proyecto: MVC, Razor Pages y Blazor Server, todas ellas generan código que se mezcla con el lenguaje de marcas (HTML) en el servidor.</p><table><thead><tr><th>CE</th><th>Descripción</th><th>Cómo se trabaja en WalaDaw</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>Se han identificado las diferencias entre la ejecución de código en el servidor y en el cliente web</td><td>En MVC y Razor Pages, el código C# se ejecuta en el servidor y genera HTML que se envía al cliente. En Blazor Server, aunque hay interactividad, el código C# sigue ejecutándose en el servidor mediante SignalR.</td></tr><tr><td><strong>b</strong></td><td>Se han reconocido las ventajas de unir ambas tecnologías en el proceso de desarrollo de programas</td><td>Las tres tecnologías permiten combinar HTML con C# en el mismo archivo (.cshtml para MVC/Razor, .razor para Blazor), facilitando el desarrollo de páginas dinámicas.</td></tr><tr><td><strong>c</strong></td><td>Se han identificado las tecnologías y frameworks relacionadas con la generación por parte del servidor de páginas web con guiones embebidos</td><td>ASP.NET Core MVC (vistas Razor), Razor Pages y Blazor Server son las tecnologías utilizadas para generar páginas web con código embebido en el lenguaje de marcas.</td></tr><tr><td><strong>d</strong></td><td>Se han utilizado estas tecnologías y frameworks para generar páginas web que incluyan interacción con el usuario</td><td>En MVC y Razor Pages se usa JavaScript/jQuery para interactividad; en Blazor Server se usan componentes C# que actualizan la UI sin recargar la página (ej: filtros de productos).</td></tr><tr><td><strong>e</strong></td><td>Se han utilizado estas tecnologías y frameworks, para generar páginas web que incluyan verificación de formularios</td><td>Las tres tecnologías usan DataAnnotations para validación: en MVC y Razor Pages con atributos en los modelos, en Blazor Server con EditForm y Validations.</td></tr><tr><td><strong>f</strong></td><td>Se han utilizado estas tecnologías y frameworks para generar páginas web que incluyan modificación dinámica de su contenido y su estructura</td><td>En MVC/Razor Pages se logra mediante AJAX o form submissions; en Blazor Server mediante actualizaciones de estado en componentes que se reflejan en la UI.</td></tr><tr><td><strong>g</strong></td><td>Se han aplicado estas tecnologías y frameworks en la programación de aplicaciones web</td><td>El proyecto usa MVC para el catálogo de productos, Razor Pages para páginas informativas, y Blazor Server para el dashboard de admin.</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>En este RA, los alumnos experimentan cómo las tres tecnologías (MVC, Razor Pages y Blazor Server) permiten generar páginas web dinámicas al mezclar código C# con HTML. Cada una tiene sus ventajas: MVC ofrece separación clara de responsabilidades, Razor Pages es ideal para páginas centradas en la vista, y Blazor Server permite interactividad rica sin escribir JavaScript. La elección depende del caso de uso específico.</p></div><hr><h3 id="ra9-desarrolla-aplicaciones-web-hibridas-seleccionando-y-utilizando-tecnologias-frameworks-servidor-y-repositorios-heterogeneos-de-informacion" tabindex="-1"><a class="header-anchor" href="#ra9-desarrolla-aplicaciones-web-hibridas-seleccionando-y-utilizando-tecnologias-frameworks-servidor-y-repositorios-heterogeneos-de-informacion"><span>RA9: Desarrolla aplicaciones web híbridas seleccionando y utilizando tecnologías, frameworks servidor y repositorios heterogéneos de información.</span></a></h3><p>Aquí entramos en librerías externas, Big Data básico, análisis.</p><table><thead><tr><th>CE</th><th>Descripción</th><th>Cómo se trabaja en WalaDaw</th></tr></thead><tbody><tr><td><strong>a</strong></td><td>Se han reconocido las ventajas que proporciona la reutilización de código y el aprovechamiento de información ya existente</td><td>El proyecto usa librerías NuGet ya existentes en lugar de reinventar la rueda.</td></tr><tr><td><strong>b</strong></td><td>Se han identificado tecnologías y frameworks aplicables en la creación de aplicaciones web híbridas</td><td>Blazor (híbrido servidor/cliente), Bootstrap (CSS), ApexCharts (gráficos).</td></tr><tr><td><strong>c</strong></td><td>Se ha creado una aplicación web que recupere y procese repositorios de información ya existentes</td><td>Consultas LINQ sobre la base de datos para obtener información de ventas, productos más vendidos, etc.</td></tr><tr><td><strong>d</strong></td><td>Se han creado repositorios específicos a partir de información existente en almacenes de información</td><td>Generación de informes y estadísticas a partir de datos existentes.</td></tr><tr><td><strong>e</strong></td><td>Se han utilizado librerías de código y frameworks para incorporar funcionalidades específicas a una aplicación web</td><td>NuGet packages: Blazor-ApexCharts para gráficos, Serilog para logging, y sistema de localización para soportar múltiples idiomas (i18n).</td></tr><tr><td><strong>f</strong></td><td>Se han programado servicios y aplicaciones web utilizando como base información y código generados por terceros</td><td>Librerías externas que se integran en la aplicación.</td></tr><tr><td><strong>g</strong></td><td>Se han analizado y utilizado librerías de código relacionadas con Big Data e inteligencia de negocios, para incorporar análisis e inteligencia de datos proveniente de repositorios</td><td>El dashboard de admin incluye gráficos de ventas usando LINQ para agregar datos. Consultas que analizan: productos más vendidos, ingresos por día, usuarios registrados. Esto es &quot;Big Data&quot; a pequeña escala: analizar datos para tomar decisiones.</td></tr><tr><td><strong>h</strong></td><td>Se han probado, depurado y documentado las aplicaciones generadas</td><td>Tests completos, código documentado, documentación del proyecto.</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>El RA9.g es uno de los favoritos de los alumnos. Les encanta hacer el dashboard de admin con gráficos. Escriben consultas LINQ que agrupan datos (group by), hacen sumas, cuentan, ordenan. Luego lo pintan en gráficos con ApexCharts. No es &quot;Big Data&quot; de verdad, pero es la base: transformar datos en información útil.</p></div><h2 id="documentacion" tabindex="-1"><a class="header-anchor" href="#documentacion"><span>Documentación</span></a></h2><p>A lo largo del proyecto, cada commit incluye documentación técnica detallada. Desde la configuración de Docker hasta la implementación de Identity, cada paso está documentado en el repo en formato Markdown, con explicaciones claras y enlaces a recursos adicionales en el directorio <code>docs/</code>.</p><div class="hint-container tip"><p class="hint-container-title">Consejos</p><p>Estos documentos son apuntes vivos. No son solo para el proyecto, sino para que los alumnos los usen como referencia en sus propios proyectos. La documentación es parte del aprendizaje y la construimos juntos a medida que avanzamos.</p></div><h2 id="reflexiones-finales" tabindex="-1"><a class="header-anchor" href="#reflexiones-finales"><span>Reflexiones Finales</span></a></h2><p>Lo que más satisfacción me produce de este enfoque es ver cómo los alumnos pasan de &quot;no sé qué es esto&quot; a &quot;esto lo sé aplicar&quot;. No aprenden tecnologías sueltas; aprenden a resolver problemas. Cuando un alumno puede explicar por qué usa Blazor en lugar de MVC para cierto caso, ha entendido algo que va más allá del código: ha aprendido a pensar como un desarrollador.</p><p>Este proyecto no pretende ser perfecto. Tiene fallos intencionados para que los detecten. Porque en la vida profesional no siempre tendrán código limpio; tendrán que mantener código de otros, arreglar desastres, entender decisiones que no tienen sentido. Este proyecto los prepara para eso.</p><p><strong>Lo que realmente aprenden:</strong></p><ul><li>A leer código de otros y entenderlo</li><li>A recibir feedback y mejorar con él</li><li>A documentar para que otros les entiendan</li><li>A probar para confiar en su código</li><li>A desplegar para que su trabajo sea visible</li></ul><p>El módulo de Desarrollo Web en Entornos Servidor no es solo &quot;aprender ASP.NET&quot;. Es aprender a construir aplicaciones web completas, desde la base de datos hasta la interfaz, pasando por seguridad, testing y despliegue. Este proyecto abarca todo eso, pero lo más importante es que los alumnos aprenden a aprender. Porque la tecnología cambia, pero saber resolver problemas no.</p><blockquote><p>&quot;En DAW no formamos programadores que solo saben usar un framework. Formamos profesionales que pueden adaptarse a cualquier tecnología porque entienden los conceptos fundamentales.&quot;</p></blockquote><p><strong>Este es el primero de varios proyectos que iré publicando</strong>. Cada uno cubrirá diferentes aspectos del ciclo: APIs, servicios, despliegue, etc. Porque una aplicación web completa no se hace con un solo proyecto.</p><p><strong>El código no se escribe solo, y el futuro se construye commit a commit.</strong> 🚀</p><hr><p><em>¿Qué aspecto del desarrollo web en entorno servidor te gustaría que profundizáramos en próximos artículos? Deja tu comentario.</em></p>`,128)])}var f=s(u,[[`render`,d]]);export{l as _pageData,f as default};